import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    def time_to_reach(point1, point2, speed):
        return euclidean_distance(point1, point2) / speed

    best_node = None
    min_penalty = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        time_to_customer = time_to_reach(cur_truck_pos, customer_pos, truck_speed)
        arrival_time = current_time + time_to_customer
        open_time, close_time = time_windows[i]
        penalty = 0

        if arrival_time > close_time:
            penalty += 1e6  # Large penalty for missing the time window
        else:
            if arrival_time < open_time:
                penalty += (open_time - arrival_time)  # Waiting time penalty

        if penalty < min_penalty:
            min_penalty = penalty
            best_node = i

    # If all customers incur a high penalty, return None to wait
    if min_penalty >= 1e6:
        return None

    return best_node

